ALTER TABLE "Settings" ADD COLUMN IF NOT EXISTS "ownerAlertEmail" TEXT;
ALTER TABLE "Settings" ADD COLUMN IF NOT EXISTS "dailyDigestEnabled" BOOLEAN NOT NULL DEFAULT true;
ALTER TABLE "Settings" ADD COLUMN IF NOT EXISTS "failedSendAlertsEnabled" BOOLEAN NOT NULL DEFAULT true;
ALTER TABLE "Settings" ADD COLUMN IF NOT EXISTS "weeklyReportEnabled" BOOLEAN NOT NULL DEFAULT true;
CREATE TABLE IF NOT EXISTS "SupportTicket" ("id" TEXT PRIMARY KEY, "accountId" TEXT NOT NULL REFERENCES "Account"("id") ON DELETE RESTRICT ON UPDATE CASCADE, "requesterUserId" TEXT, "subject" TEXT NOT NULL, "body" TEXT NOT NULL, "status" TEXT NOT NULL DEFAULT 'open', "priority" TEXT NOT NULL DEFAULT 'normal', "source" TEXT NOT NULL DEFAULT 'app', "createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, "updatedAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE INDEX IF NOT EXISTS "SupportTicket_accountId_status_createdAt_idx" ON "SupportTicket"("accountId", "status", "createdAt");
CREATE TABLE IF NOT EXISTS "SavedView" ("id" TEXT PRIMARY KEY, "accountId" TEXT NOT NULL REFERENCES "Account"("id") ON DELETE RESTRICT ON UPDATE CASCADE, "name" TEXT NOT NULL, "viewType" TEXT NOT NULL DEFAULT 'leads', "filtersJson" JSONB NOT NULL, "isDefault" BOOLEAN NOT NULL DEFAULT false, "createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, "updatedAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE INDEX IF NOT EXISTS "SavedView_accountId_viewType_idx" ON "SavedView"("accountId", "viewType");
CREATE TABLE IF NOT EXISTS "BackupExport" ("id" TEXT PRIMARY KEY, "accountId" TEXT NOT NULL REFERENCES "Account"("id") ON DELETE RESTRICT ON UPDATE CASCADE, "exportType" TEXT NOT NULL, "status" TEXT NOT NULL DEFAULT 'ready', "recordCount" INTEGER NOT NULL DEFAULT 0, "payloadJson" JSONB NOT NULL, "createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, "expiresAt" TIMESTAMP(3));
CREATE INDEX IF NOT EXISTS "BackupExport_accountId_exportType_createdAt_idx" ON "BackupExport"("accountId", "exportType", "createdAt");
CREATE TABLE IF NOT EXISTS "NotificationEvent" ("id" TEXT PRIMARY KEY, "accountId" TEXT NOT NULL REFERENCES "Account"("id") ON DELETE RESTRICT ON UPDATE CASCADE, "channel" TEXT NOT NULL, "eventType" TEXT NOT NULL, "status" TEXT NOT NULL DEFAULT 'queued', "recipient" TEXT, "subject" TEXT, "bodySnapshot" TEXT NOT NULL, "failureReason" TEXT, "createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, "sentAt" TIMESTAMP(3));
CREATE INDEX IF NOT EXISTS "NotificationEvent_accountId_eventType_status_createdAt_idx" ON "NotificationEvent"("accountId", "eventType", "status", "createdAt");
